export const Reducer = (state = initialState, action) => {
    switch (action.type) {
        case "GET_PRODUCT" : {
            return {...state, product: action.payload}
        }

        case ADD_TO_BASKET : {
            const fount = state.basket.find(el => el.id === action.payload.id)
            if (fount) {
                return {...state, basket: state.basket.map(el => el.id === fount.id ? {...el, quantity: el.quantity +1} : el)}
            } else {
                return {...state, basket: [...state.basket, {...action.payload, quantity: 1}]}
            }
        }

        case DEC_BASKET : {
            return {...state, basket: state.basket.map(el => {
                if (el.id === action.payload.id) {
                    if (el.quantity > 1) {
                        return {...el, quantity: el.quantity -1}
                    } else return el
                } else return el
                })}
        }

        case DELETE_BASKET : {
            return {...state, basket: state.basket.filter(el => el.id !== action.payload.id)}
        }

        case ADD_TO_FAVORITE : {
            const fount = state.favorite.find(el => el.id === action.payload.id)
            if (fount) {
                return {...state, favorite: state.favorite.filter(el => el.id !== fount.id)}
            } else {
                return {...state, favorite: [...state.favorite, action.payload]}
            }
        }

        case CURREN_Q : {
            return {...state, defCurren: action.payload.target.value}
        }


        default:
            return state
    }
}








